        {/* Bank preview */}
        {restaurant?.bankDetails?.accountNumber && (
          <div style={{background:'#F0FDF4',borderRadius:12,padding:14,marginBottom:20,display:'flex',alignItems:'center',gap:12,border:`1px solid #BBF7D0`}}>
            <span style={{fontSize:28}}>🏦</span>
            <div>
              <div style={{fontWeight:700,fontSize:15}}>{restaurant.bankDetails.bankName}</div>
              <div style={{color:C.gray,fontSize:13}}>{restaurant.bankDetails.accountNumber} · {restaurant.bankDetails.accountName}</div>
            </div>
            <span style={{marginLeft:'auto',background:'#DCFCE7',color:C.success,padding:'4px 12px',borderRadius:20,fontWeight:700,fontSize:12}}>✓ Active</span>
          </div>
        )}

        {/* Amount input + quick picks */}
        <label style={{fontSize:13,fontWeight:700,display:'block',marginBottom:8}}>Amount to Withdraw (₦)</label>
        <div style={{display:'flex',gap:10,marginBottom:12,flexWrap:'wrap'}}>
          {[5000,10000,20000,50000].map(amt=>(
            <button key={amt} onClick={()=>setWAmount(String(amt))}
              style={{...btn(Number(wAmount)===amt?C.success:'#f0f0f0', Number(wAmount)===amt?'#fff':C.gray),borderRadius:20,padding:'8px 18px',fontSize:13}}>
              ₦{(amt/1000).toFixed(0)}k
            </button>
          ))}
        </div>
        <div style={{display:'flex',gap:12,alignItems:'flex-start',marginBottom:8}}>
          <div style={{flex:1}}>
            <input
              style={{...inp,fontSize:18,fontWeight:700,height:52}}
              type="number"
              placeholder="Or enter custom amount"
              value={wAmount}
              onChange={e=>setWAmount(e.target.value)}
            />
            {wAmount&&Number(wAmount)>0&&(
              <div style={{marginTop:6,fontSize:13,color:C.gray}}>
                You will receive: <strong style={{color:C.success,fontSize:15}}>₦{Number(wAmount).toLocaleString()}</strong> to your bank account
              </div>
            )}
          </div>
        </div>
        <button
          style={{...btn(C.success),padding:'14px 36px',fontSize:16,marginTop:8,opacity:(!wAmount||Number(wAmount)<100||wLoading)?0.5:1}}
          onClick={requestWithdrawal}
          disabled={!wAmount||Number(wAmount)<100||wLoading}
        >
          {wLoading?'⏳ Submitting request...':'↗ Request Withdrawal'}
        </button>
      </div>

      {/* Withdrawal history */}
      <div style={card}>
        <h2 style={{fontSize:18,fontWeight:800,marginBottom:16}}>Withdrawal History</h2>
        {loading?(
          <p style={{color:C.gray,textAlign:'center',padding:20}}>Loading...</p>
        ):withdrawals.length===0?(
          <div style={{textAlign:'center',padding:48}}>
            <div style={{fontSize:52,marginBottom:12}}>💸</div>
            <p style={{color:C.gray,fontSize:15,fontWeight:600}}>No withdrawals yet</p>
            <p style={{color:C.gray,fontSize:13,marginTop:4}}>Request your first withdrawal above</p>
          </div>
        ):withdrawals.map(w=>(
          <div key={w._id} style={{display:'flex',justifyContent:'space-between',alignItems:'center',padding:'16px 0',borderBottom:`1px solid ${C.border}`}}>
            <div style={{display:'flex',alignItems:'center',gap:14}}>
              <div style={{width:48,height:48,borderRadius:12,background:(SC[w.status]||C.gray)+'22',display:'flex',alignItems:'center',justifyContent:'center',fontSize:22}}>
                {statusIcon[w.status]||'🕐'}
              </div>
              <div>
                <div style={{fontWeight:800,fontSize:17}}>₦{w.amount?.toLocaleString()}</div>
                <div style={{color:C.gray,fontSize:12,marginTop:2}}>
                  {new Date(w.createdAt).toLocaleDateString('en-GB',{day:'numeric',month:'short',year:'numeric'})}
                  {' · '}{w.bankDetails?.bankName}{' · ****'}{w.bankDetails?.accountNumber?.slice(-4)}
                </div>
                {w.adminNote&&<div style={{color:C.warning,fontSize:12,marginTop:3}}>📝 {w.adminNote}</div>}
              </div>
            </div>
            <div style={{textAlign:'right'}}>
              <span style={{background:(SC[w.status]||C.gray)+'22',color:SC[w.status]||C.gray,padding:'5px 14px',borderRadius:20,fontSize:13,fontWeight:700,textTransform:'capitalize',display:'inline-block',marginBottom:4}}>
                {w.status}
              </span>
              {w.status==='processing'&&<div style={{color:C.gray,fontSize:11}}>Paystack transfer sent</div>}
              {w.status==='paid'&&<div style={{color:C.success,fontSize:11,fontWeight:600}}>✓ Paid to your bank</div>}
              {w.status==='rejected'&&<div style={{color:C.error,fontSize:11}}>Contact support</div>}
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

function Settings() {
  const {restaurant,setRestaurant}=useAuth();
  const [form,setForm]=useState({name:'',phone:'',address:'',cuisineType:'',description:'',isOpen:false,openTime:'08:00',closeTime:'22:00'});
  const [bankForm,setBankForm]=useState({bankName:'',accountNumber:'',accountName:'',bankCode:''});
  const [saving,setSaving]=useState(false);
  const [savingBank,setSavingBank]=useState(false);

  useEffect(()=>{
    if(restaurant){
      setForm({name:restaurant.name||'',phone:restaurant.phone||'',address:restaurant.address||'',cuisineType:restaurant.cuisineType||'',description:restaurant.description||'',isOpen:restaurant.isOpen||false,openTime:restaurant.openTime||'08:00',closeTime:restaurant.closeTime||'22:00'});
      if(restaurant.bankDetails) setBankForm(restaurant.bankDetails);
    }
  },[restaurant]);

  const save=async()=>{ setSaving(true); try{ const {data}=await api.patch('/restaurants/me',form); setRestaurant(data); alert('Settings saved!'); }catch{ alert('Failed to save'); }finally{ setSaving(false); } };
  const saveBank=async()=>{
    if(!bankForm.accountNumber||!bankForm.bankName||!bankForm.accountName) return alert('Please fill in all bank details');
    setSavingBank(true);
    try{ const {data}=await api.patch('/restaurants/me',{bankDetails:bankForm}); setRestaurant(data); alert('✅ Bank details saved!'); }
    catch{ alert('Failed to save bank details'); }finally{ setSavingBank(false); }
  };

  return (
    <div style={{padding:28,overflowY:'auto',flex:1}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:24}}>
        <h1 style={{fontSize:26,fontWeight:800}}>Settings</h1>
        <button style={btn(C.primary)} onClick={save} disabled={saving}>{saving?'Saving...':'💾 Save Changes'}</button>
      </div>
      <div style={{...card,marginBottom:16}}>
        <h3 style={{fontWeight:800,marginBottom:14}}>🟢 Restaurant Status</h3>
        <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:4}}>
          <span style={{fontWeight:600}}>Currently {form.isOpen?'Open':'Closed'}</span>
          <input type="checkbox" checked={form.isOpen} onChange={e=>setForm({...form,isOpen:e.target.checked})} style={{width:22,height:22,cursor:'pointer',accentColor:C.primary}} />
        </div>
        <p style={{color:C.gray,fontSize:13,marginBottom:14}}>{form.isOpen?'Accepting orders from customers':'Not accepting orders'}</p>
        <div style={{display:'grid',gridTemplateColumns:'1fr auto 1fr',gap:12,alignItems:'end'}}>
          <div><label style={{fontSize:13,fontWeight:600,display:'block',marginBottom:6}}>Opens</label><input style={inp} value={form.openTime} onChange={e=>setForm({...form,openTime:e.target.value})} /></div>
          <span style={{paddingBottom:10,color:C.gray,fontWeight:700}}>→</span>
          <div><label style={{fontSize:13,fontWeight:600,display:'block',marginBottom:6}}>Closes</label><input style={inp} value={form.closeTime} onChange={e=>setForm({...form,closeTime:e.target.value})} /></div>
        </div>
      </div>
      <div style={{...card,marginBottom:16}}>
        <h3 style={{fontWeight:800,marginBottom:14}}>🏪 Restaurant Details</h3>
        <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:14}}>
          {[['Restaurant Name','name'],['Phone','phone'],['Address','address'],['Cuisine Type','cuisineType']].map(([l,k])=>(
            <div key={k}><label style={{fontSize:13,fontWeight:600,display:'block',marginBottom:6}}>{l}</label><input style={inp} value={form[k]} onChange={e=>setForm({...form,[k]:e.target.value})} /></div>
          ))}
        </div>
        <div style={{marginTop:14}}><label style={{fontSize:13,fontWeight:600,display:'block',marginBottom:6}}>Description</label><textarea style={{...inp,height:90,resize:'vertical'}} value={form.description} onChange={e=>setForm({...form,description:e.target.value})} /></div>
      </div>
      <div style={{...card,borderTop:`3px solid ${C.success}`}}>
        <h3 style={{fontWeight:800,marginBottom:4}}>🏦 Bank Details for Withdrawals</h3>
        <p style={{color:C.gray,fontSize:13,marginBottom:16}}>Required to receive withdrawal payments via Paystack</p>
        <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:14,marginBottom:14}}>
          <div>
            <label style={{fontSize:13,fontWeight:600,display:'block',marginBottom:6}}>Bank Name</label>
            <select style={{...inp,cursor:'pointer',background:'#fff',height:44}} value={bankForm.bankName}
              onChange={e=>{ const s=NIGERIAN_BANKS.find(b=>b.name===e.target.value); setBankForm({...bankForm,bankName:e.target.value,bankCode:s?.code||''}); }}>
              <option value="">Select your bank...</option>
              {NIGERIAN_BANKS.map(bank=>(<option key={bank.code} value={bank.name}>{bank.name}</option>))}
            </select>
          </div>
          <div>
            <label style={{fontSize:13,fontWeight:600,display:'block',marginBottom:6}}>Account Number</label>
            <input style={inp} placeholder="10-digit number" maxLength={10} value={bankForm.accountNumber} onChange={e=>setBankForm({...bankForm,accountNumber:e.target.value})} />
          </div>
          <div>
            <label style={{fontSize:13,fontWeight:600,display:'block',marginBottom:6}}>Account Name</label>
            <input style={inp} placeholder="As on bank records" value={bankForm.accountName} onChange={e=>setBankForm({...bankForm,accountName:e.target.value})} />
          </div>
          <div>
            <label style={{fontSize:13,fontWeight:600,display:'block',marginBottom:6}}>Bank Code <span style={{color:C.success,fontSize:11}}>(auto-filled)</span></label>
            <input style={{...inp,background:'#f9fafb',color:C.gray}} value={bankForm.bankCode} readOnly placeholder="Auto-filled when you select a bank" />
          </div>
        </div>
        <button style={{...btn(C.success),padding:'10px 24px',fontSize:14}} onClick={saveBank} disabled={savingBank}>
          {savingBank?'Saving...':'✓ Save Bank Details'}
        </button>
      </div>
    </div>
  );
}

function AppContent() {
  const {user}=useAuth();
  const [page,setPage]=useState('overview');
  const [pendingCount,setPendingCount]=useState(0);
  useEffect(()=>{ if(user) api.get('/orders/restaurant').then(r=>setPendingCount(r.data.filter(o=>o.status==='pending').length)).catch(()=>{}); },[user]);
  if(!user) return <Login />;
  const pages={overview:<Overview setPage={setPage}/>,orders:<Orders/>,menu:<Menu/>,analytics:<Analytics/>,wallet:<Wallet/>,settings:<Settings/>};
  return (
    <div style={{display:'flex',width:'100%'}}>
      <Sidebar page={page} setPage={setPage} pendingCount={pendingCount} />
      <div style={{flex:1,overflowY:'auto',background:'#F8F8F8'}}>{pages[page]||<Overview setPage={setPage}/>}</div>
    </div>
  );
}

export default function App() { return <AuthProvider><AppContent /></AuthProvider>; }
